      continue;
    uint16_t s0_raw = static_cast<uint16_t>(src0.read_lane(wf, lane));
    float s0 = util::f16_to_f32(s0_raw);
    if (inst_.abs & (1u << 0))
      s0 = std::fabs(s0);
    if (inst_.neg & (1u << 0))
      s0 = -s0;
    uint32_t mask = src1.read_lane(wf, lane);
